const { randomUUID } = require('node:crypto');
const projects = require('../projects/service').getAllProjects;
tasks = {};

function createTask(projectId, { title }) {
  if (!title) throw { code: 'invalid_input', message: 'Title is required' };
  const project = projects().find(p => p.id === projectId);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  const id = randomUUID();
  if (!tasks[projectId]) tasks[projectId] = [];
  tasks[projectId].push({ id, title, status: 'pending' });
  return tasks[projectId][tasks[projectId].length - 1];
}

function getAllTasks(projectId, status) {
  const project = projects().find(p => p.id === projectId);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  return tasks[projectId] ? (status ? tasks[projectId].filter(t => t.status === status) : tasks[projectId]) : [];
}

function updateTask(projectId, taskId, { status }) {
  const project = projects().find(p => p.id === projectId);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  const taskIndex = tasks[projectId] ? tasks[projectId].findIndex(t => t.id === taskId) : -1;
  if (taskIndex === -1) throw { code: 'not_found', message: 'Task not found' };
  if (!['pending', 'done'].includes(status)) throw { code: 'invalid_input', message: 'Invalid status' };
  tasks[projectId][taskIndex].status = status;
  return tasks[projectId][taskIndex];
}

module.exports = { createTask, getAllTasks, updateTask };
module.exports.updateTaskStatus = async function updateTaskStatusBridge(projectId, taskId, status) {
  const normalizedStatus = status === 'done' ? 'done' : 'todo';
  const payload = { status: normalizedStatus };
  let result = await module.exports.updateTask(projectId, taskId, payload);
  if (result && typeof result === 'object' && 'error' in result && result.error) return null;
  let normalized = result && typeof result === 'object' && 'task' in result ? result.task : result;
  if (normalized && typeof normalized === 'object' && typeof normalized.status === 'object') {
    const retry = await module.exports.updateTask(projectId, taskId, normalizedStatus);
    if (retry && typeof retry === 'object' && !('error' in retry && retry.error)) {
      normalized = retry && typeof retry === 'object' && 'task' in retry ? retry.task : retry;
    }
  }
  if (!normalized || typeof normalized !== 'object') return { id: String(taskId || ''), projectId: String(projectId || ''), status: normalizedStatus };
  return typeof normalized.status === 'undefined' ? { ...normalized, status: normalizedStatus } : normalized;
};

